"""Static dashboard index_html asset."""

INDEX_HTML = '<!doctype html>\n<html lang="ja">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover">\n<meta name="description" content="日本株のモメンタムを調査優先度・相対強度・業種・品質から深掘りする研究ダッシュボード">\n<meta name="theme-color" content="#0b1220">\n<title>Momentum Chimpan | 引け後リサーチ</title>\n<link rel="stylesheet" href="assets/styles.css">\n</head>\n<body>\n<a class="skip-link" href="#main">本文へ移動</a>\n<header class="topbar">\n  <div class="brand"><span class="brand-mark">M</span><span>Momentum Chimpan</span></div>\n  <button id="navToggle" class="nav-toggle" aria-label="メニューを開く">☰</button>\n  <nav id="siteNav" class="site-nav" aria-label="主要ナビゲーション">\n    <a href="#overview">概況</a><a href="#actions">今日の候補</a><a href="#ranking">Top100</a><a href="#changes">変化</a><a href="#sectors">業種</a><a href="#relative">相対強度</a><a href="#quality">品質</a><a href="#research">検証</a>\n  </nav>\n</header>\n<main id="main">\n<section id="overview" class="hero section-shell">\n  <div class="hero-copy">\n    <div class="eyebrow">AFTER MARKET RESEARCH</div>\n    <h1>今日、何から調べるか。</h1>\n    <p>順位だけでなく、変化・相対強度・業種・品質・実績を一つの画面で確認します。売買推奨ではありません。</p>\n    <div class="hero-meta"><span id="reportDate">—</span><span id="priceDate">株価日 —</span><span id="freshBadge" class="status-pill">確認中</span></div>\n  </div>\n  <div id="regimeCard" class="regime-card"></div>\n</section>\n<section class="section-shell metric-grid" id="summaryMetrics" aria-label="主要指標"></section>\n<section id="actions" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">DAILY ACTION LIST</div><h2>今日の調査候補</h2><p>Aは必ず確認、Bは時間があれば確認。候補がなければ無理に作りません。</p></div><div id="actionCounts" class="count-strip"></div></div>\n  <div id="actionCards" class="action-grid"></div>\n</section>\n<section id="ranking" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">MOMENTUM TOP100</div><h2>ランキングを探索</h2><p>銘柄名・コード検索と、業種・品質・ライフサイクル・変化で絞り込めます。</p></div><button id="resetFilters" class="ghost-button">条件をリセット</button></div>\n  <div class="filter-panel">\n    <label class="search-field"><span>検索</span><input id="searchInput" type="search" placeholder="コード・銘柄名"></label>\n    <label><span>業種</span><select id="sectorFilter"><option value="">すべて</option></select></label>\n    <label><span>品質</span><select id="qualityFilter"><option value="">すべて</option><option>A</option><option>B</option><option>C</option><option>D</option></select></label>\n    <label><span>局面</span><select id="lifecycleFilter"><option value="">すべて</option></select></label>\n    <label><span>並び順</span><select id="sortFilter"><option value="rank">Momentum順位</option><option value="score">Momentumスコア</option><option value="return20">20日騰落率</option><option value="volume">出来高倍率</option><option value="relative">相対強度</option></select></label>\n    <label class="check"><input id="newOnly" type="checkbox"><span>新規のみ</span></label>\n    <label class="check"><input id="risingOnly" type="checkbox"><span>急上昇のみ</span></label>\n  </div>\n  <div class="table-meta"><span id="rankingCount">0件</span><span>行を選択すると詳細を表示</span></div>\n  <div class="table-wrap"><table class="data-table"><thead><tr><th>順位</th><th>銘柄</th><th>区分</th><th>Score</th><th>20日</th><th>出来高</th><th>相対</th><th>品質</th><th>変化</th></tr></thead><tbody id="rankingBody"></tbody></table></div>\n  <div id="stockDetail" class="stock-detail empty-state">ランキングから銘柄を選択してください。</div>\n</section>\n<section id="changes" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">WHAT CHANGED</div><h2>前回からの変化</h2><p>新規、継続、脱落を分け、現在の優先順位が変わった理由を確認します。</p></div></div>\n  <div id="changeTabs" class="tabs"><button data-change="新規" class="active">新規</button><button data-change="継続">継続</button><button data-change="脱落">脱落</button></div>\n  <div id="changeList" class="list-grid"></div>\n</section>\n<section id="sectors" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">SECTOR ROTATION</div><h2>業種の広がりと主導株</h2><p>個別ランキングを変えず、業種内の広がりと相対的な強さを表示します。</p></div></div>\n  <div class="split-grid"><div><h3>33業種モメンタム</h3><div id="sectorList" class="bar-list"></div></div><div><h3>業種リーダー候補</h3><div id="leaderList" class="compact-list"></div></div></div>\n</section>\n<section id="relative" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">RELATIVE STRENGTH</div><h2>市場・同業を上回る強さ</h2><p>20日・60日で市場中央値と業種中央値を比較し、強さの推移も確認します。</p></div></div>\n  <div id="relativeCards" class="list-grid"></div>\n</section>\n<section id="quality" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">DATA QUALITY</div><h2>ランキングの信頼性</h2><p>品質CはA候補に昇格できず、品質Dは見送り。Momentumスコアと順位自体は変更しません。</p></div><div id="qualityCounts" class="count-strip"></div></div>\n  <div id="qualityWarnings" class="warning-list"></div>\n</section>\n<section id="research" class="section-shell">\n  <div class="section-head"><div><div class="eyebrow">RESEARCH & OPERATIONS</div><h2>検証と運用品質</h2><p>ペーパー検証、シグナル実績、Forward Evidence、日次運用の現在地です。</p></div><a class="download-button" href="downloads/daily_report.xlsx" download>Excelをダウンロード</a></div>\n  <div class="research-grid"><article class="panel"><h3>ペーパーポートフォリオ</h3><div id="paperSummary"></div><div id="paperPositions" class="compact-list"></div></article><article class="panel"><h3>シグナル実績</h3><div id="signalPerformance" class="compact-list"></div></article><article class="panel"><h3>研究エビデンス</h3><div id="evidenceList" class="compact-list"></div></article><article class="panel"><h3>運用品質</h3><div id="operationsList" class="compact-list"></div></article></div>\n</section>\n</main>\n<footer><div>Momentum Chimpan — research priority support, not investment advice.</div><div id="footerVersion"></div></footer>\n<script src="assets/data.js"></script><script src="assets/app.js"></script>\n</body></html>'
